import { useState } from "react";
import API_URL from "../api"; // Import backend URL

// const token = localStorage.getItem("token"); // Get token from storage
// const response = await fetch(`${API_URL}/api/capsules`, {
//   method: "POST",
//   headers: {
//     "Content-Type": "application/json",
//     "Authorization": `Bearer ${token}` // Add token here
//   },
//   body: JSON.stringify(newCapsule),
// });

function CreateCapsule() {
  const [title, setTitle] = useState("");
  const [date, setDate] = useState("");
  const [content, setContent] = useState("");
  const [message, setMessage] = useState(""); // Success/Error message

  const handleSubmit = async (e) => {
    e.preventDefault();

    const newCapsule = { title, unlockDate: date, content };

    try {
      const response = await fetch(`${API_URL}/api/capsules`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(newCapsule),
      });

      if (response.ok) {
        setMessage("Capsule created successfully!");
        setTitle("");
        setDate("");
        setContent("");
      } else {
        setMessage("Error creating capsule.");
      }
    } catch (error) {
      console.error("Error:", error);
      setMessage("Server error. Try again later.");
    }
  };

  return (
    <div>
      <h1>Create a Time Capsule</h1>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          placeholder="Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          required
        />
        <br />
        <input
          type="date"
          value={date}
          onChange={(e) => setDate(e.target.value)}
          required
        />
        <br />
        <textarea
          placeholder="Add your content"
          value={content}
          onChange={(e) => setContent(e.target.value)}
          required
        />
        <br />
        <button type="submit">Create Capsule</button>
      </form>

      {message && <p>{message}</p>} {/* Show success/error message */}
    </div>
  );
}

export default CreateCapsule;
